class Solution:
    def averageWaitingTime(self, customers):
        finish_times = []
        prev_finish = 0
        for arrival, prep in customers:
            begin = arrival if arrival > prev_finish else prev_finish
            prev_finish = begin + prep
            finish_times.append(prev_finish)
        total_wait = sum(f - c[0] for f, c in zip(finish_times, customers))
        return total_wait / len(customers)

