var averageWaitingTime = function(customers) {
  let currentTime = 0;
  let totalWait = 0;
  for (const [arrival, prep] of customers) {
    currentTime = Math.max(currentTime, arrival) + prep;
    totalWait += currentTime - arrival;
  }
  return totalWait / customers.length;
};
